const searchBlocks=document.querySelectorAll(".search-block");searchBlocks.length&&searchBlocks.forEach(e=>{const t=e.querySelector(".search-block__input"),c=e.querySelector(".search-block__results");document.addEventListener("click",s=>{const l=s.target.closest(".search-block__field"),i=s.target.closest(".search-block__results"),o=s.target.closest(".search-block__reset");!l&&!i?(c.classList.remove("is-open"),e.classList.remove("is-active")):o&&(c.classList.remove("is-open"),e.classList.remove("is-active"),t.value="",t.parentElement.classList.remove("is-filled"))}),t.addEventListener("focus",s=>{s.currentTarget.value.length>0&&(c.classList.add("is-open"),e.classList.add("is-active"))})});
